const item = $input.first();
const json = item.json ?? {};
const binary = item.binary ?? {};

const triggerJson = $('Local File Trigger').first().json ?? {};

const filepath =
  json.path ??
  json.filePath ??
  json.filepath ??
  json.file?.path ??
  json.data?.path ??
  triggerJson.path ??
  triggerJson.filePath ??
  triggerJson.filepath ??
  triggerJson.file?.path ??
  triggerJson.data?.path ??
  null;

if (!filepath || typeof filepath !== 'string') {
  throw new Error(
    `Missing filepath from local file trigger payload. Current keys: ${Object.keys(json).join(', ')} | Trigger keys: ${Object.keys(triggerJson).join(', ')}`
  );
}

const filename =
  json.fileName ??
  json.filename ??
  triggerJson.fileName ??
  triggerJson.filename ??
  filepath.split('/').pop();

const binaryKey = Object.keys(binary)[0];
const binaryEntry = binaryKey ? binary[binaryKey] : null;

let content = '';

if (binaryEntry?.data && typeof binaryEntry.data === 'string') {
  const buffer = Buffer.from(binaryEntry.data, 'base64');
  content = buffer.toString('utf8');
}

content = content.replace(/^\uFEFF/, '');

if (!content || !content.trim()) {
  throw new Error('Missing or empty file content after reading from disk');
}

const modifiedEpoch =
  json.modifiedAt ??
  json.mtime ??
  json.lastModified ??
  triggerJson.modifiedAt ??
  triggerJson.mtime ??
  triggerJson.lastModified ??
  null;

let projectSlug;
const match = filepath.match(/\/inbox\/([^/]+)\/[^/]+$/);

if (match) {
  projectSlug = match[1];
}

const output = {
  filepath,
  filename,
  content,
  modifiedEpoch
};

if (projectSlug) {
  output.project_slug = projectSlug;
}

return [{ json: output }];

const base = $('Normalize File Payload').first().json;
const ingestResult = $json ?? {};

return [{
  json: {
    success: true,
    filepath: base.filepath,
    filename: base.filename,
    derivedProjectSlug: base.project_slug ?? null,
    ingestResult
  }
}];
